// Bulk Configuration
package bulkconfiguration

import (
	"context"
	"time"

	"github.com/arminguenther/xeruspower-go/v40211/event/userevent"
	"github.com/arminguenther/xeruspower-go/v40211/idl"
)

// Error codes
const (
	SUCCESS                    int32 = 0 // The operation was successful
	ERR_FILTER_NAME_UNKNOWN    int32 = 1 // A referenced filter name is unknown
	ERR_FILTER_TYPE_READONLY   int32 = 2 // A referenced filter can't be overridden
	ERR_PROFILE_ALREADY_EXISTS int32 = 3 // A profile with the given name already exists
	ERR_PROFILE_DOES_NOT_EXIST int32 = 4 // A profile with the given name does not exist
	ERR_PROFILE_IS_DEFAULT     int32 = 5 // The selected profile is the current default profile
	ERR_PROFILE_IS_BUILTIN     int32 = 6 // The selected profile is the builtin profile
	ERR_PROFILE_NAME_TOO_LONG  int32 = 7 // The profile name is too long
	ERR_PROFILE_NAME_INVALID   int32 = 8 // The profile name contains invalid characters
	ERR_PROFILE_TOO_MANY       int32 = 9 // The maximum number of profiles already exist.
)

// Bulk Configuration Interface
type BulkConfiguration interface {
	idl.Object

	// Retrieve the status of the last bulk configuration restore
	// operation.
	//
	//	@param status     Result: Bulk configuration restore status
	//	@param timeStamp  Result: Time of last restore operation (UNIX timestamp, UTC)
	GetStatus(ctx context.Context) (status Status, timeStamp time.Time, err error)

	// Retrieve the list of supported filters.
	//
	//	@return List of supported filters
	GetFilters(ctx context.Context) ([]Filter, error)

	// Retrieve the configured filter profiles.
	//
	//	@return List of filter profiles
	GetFilterProfiles(ctx context.Context) ([]FilterProfile, error)

	// Add a new filter profile.
	//
	//	@param profile  The new filter profile
	//
	//	@return SUCCESS                    if OK
	//	@return ERR_FILTER_NAME_UNKNOWN    if a referenced filter name is unknown
	//	@return ERR_FILTER_TYPE_READONLY   if a referenced filter can't be overridden
	//	@return ERR_PROFILE_ALREADY_EXISTS if a profile with the given name already exists
	//	@return ERR_PROFILE_IS_BUILTIN     if the selected profile is the builtin profile
	//	@return ERR_PROFILE_NAME_TOO_LONG  if the profile name is too long
	//	@return ERR_PROFILE_NAME_INVALID   if the profile name contains invalid characters
	//	@return ERR_PROFILE_TOO_MANY       if the maximum number of profiles already exist
	AddFilterProfile(ctx context.Context, profile FilterProfile) (int32, error)

	// Modify an existing filter profile.
	//
	//	@param profile  The updated filter profile
	//
	//	@return SUCCESS                    if OK
	//	@return ERR_FILTER_NAME_UNKNOWN    if a referenced filter name is unknown
	//	@return ERR_FILTER_TYPE_READONLY   if a referenced filter can't be overridden
	//	@return ERR_PROFILE_DOES_NOT_EXIST if a profile with the given name does not exist
	//	@return ERR_PROFILE_IS_BUILTIN     if the selected profile is the builtin profile
	ModifyFilterProfile(ctx context.Context, profile FilterProfile) (int32, error)

	// Delete an existing filter profile.
	//
	//	@param profileName  The name of the profile to be deleted
	//
	//	@return SUCCESS                    if OK
	//	@return ERR_PROFILE_DOES_NOT_EXIST if a profile with the given name does not exist
	//	@return ERR_PROFILE_IS_DEFAULT     if the selected profile is the current default profile
	//	@return ERR_PROFILE_IS_BUILTIN     if the selected profile is the builtin profile
	DeleteFilterProfile(ctx context.Context, profileName string) (int32, error)

	// Retrieve the name of the currently selected default profile.
	//
	//	@return  The name of the current default profile
	GetDefaultFilterProfileName(ctx context.Context) (string, error)

	// Select a new default filter profile.
	//
	//	@param profileName  The name of the new default profile
	//
	//	@return SUCCESS                    if OK
	//	@return ERR_PROFILE_DOES_NOT_EXIST if a profile with the given name does not exist
	SelectDefaultFilterProfile(ctx context.Context, profileName string) (int32, error)

	// Get settings
	//
	//	@return Settings
	GetSettings(ctx context.Context) (Settings, error)

	// Set settings
	//
	// NOTE: The builtin profile will be ignored when present in the list of filter profiles.
	//
	//	@param settings  The settings to set
	//
	//	@return SUCCESS                    if OK
	//	@return ERR_FILTER_NAME_UNKNOWN    if a referenced filter name is unknown
	//	@return ERR_FILTER_TYPE_READONLY   if a referenced filter can't be overridden
	//	@return ERR_PROFILE_ALREADY_EXISTS if the settings contain multiple profiles with the same name
	//	@return ERR_PROFILE_NAME_TOO_LONG  if the profile name is too long
	//	@return ERR_PROFILE_NAME_INVALID   if the profile name contains invalid characters
	//	@return ERR_PROFILE_TOO_MANY       if the settings contain too many profiles
	//	@return ERR_PROFILE_DOES_NOT_EXIST if a profile with the given name does not exist
	SetSettings(ctx context.Context, settings Settings) (int32, error)
}

// Status of the last bulk configuration restore operation
type Status int

const (
	UNKNOWN         Status = iota // No bulk configuration was done yet
	UPLOAD_FAILED                 // Uploading a bulk configuration failed
	RESTORE_PENDING               // Restore is pending
	RESTORE_OK                    // Restoring bulk configuration successful
	RESTORE_FAILED                // Restoring bulk configuration failed
)

// These are the supported supported filter types.
type FilterType int

const (
	WHITELIST FilterType = iota // Whitelist filter (value is part of the bulk configuration)
	BLACKLIST                   // Blacklist filter (value is not part of the bulk configuration)
)

// This structure defines a filter.
type Filter struct {
	Name        string   // internal name of the filter
	DisplayName string   // name of the filter in the user interface
	NoOverride  bool     // true if filter is always active and has a fixed type
	BulkOnly    bool     // true if filter is not for backup
	RuleSpecs   []string // filter rule specifications (used only internally)
}

// Filter profiles are named collections of filters.
//
// Custom filter profiles inherit all filters from the builtin profile, i.e. if the filter profile
// is empty it is identical to the builtin profile. The type for most of the inherited filters can
// be changed in the derived profile. Only filters with the noOverride flag set are unchangable.
type FilterProfile struct {
	Name                string                // name of the filter profile
	Description         string                // description of the filter profile
	FilterNameToTypeMap map[string]FilterType // map filter name to type
}

// Settings
type Settings struct {
	FilterProfiles     []FilterProfile // Defined filter profiles
	DefaultProfileName string          // Name of the default profile
}

// Event: Bulk configuration settings changed
type SettingsChangedEvent interface {
	userevent.UserEvent
	isSettingsChangedEvent()
}

// Event: Bulk configuration saved (also used for saving config backup)
type SavedEvent interface {
	userevent.UserEvent
	IsBackup() bool // true if the event is caused by saving a full configuration backup
	isSavedEvent()
}

// Event: Bulk configuration restored (also used for restoring config backup)
type RestoredEvent interface {
	userevent.UserEvent
	IsBackup() bool // true if the event is caused by restoring a full configuration backup
	isRestoredEvent()
}
